class Solution:
    def minOperationsToMakeMedianK(self, nums, k):
        nums = sorted(nums)
        m = len(nums) // 2
        cost = 0
        for i in range(len(nums)):
            if i <= m and nums[i] > k:
                cost += nums[i] - k
            elif i >= m and nums[i] < k:
                cost += k - nums[i]
        return cost

