class Solution:
    def minOperationsToMakeMedianK(self, nums, k):
        nums.sort()
        m = len(nums) // 2
        cost = 0
        for i, v in enumerate(nums):
            if i <= m and v > k:
                cost += v - k
            elif i >= m and v < k:
                cost += k - v
        return cost

