var minOperationsToMakeMedianK = function(nums, k) {
    nums.sort((a, b) => a - b);
    const m = Math.floor(nums.length / 2);
    let cost = 0;
    for (let i = 0; i < nums.length; i++) {
        if (i <= m && nums[i] > k) cost += nums[i] - k;
        else if (i >= m && nums[i] < k) cost += k - nums[i];
    }
    return cost;
};
